### 1. Создаем структуру проекта
Создадим три файла: `main.cpp`, `sort.h`, `sort.cpp` и, если нужно, `utils.h`, но мы его использовать не будем для простоты.

#### 1.1 `sort.h`
```cpp
#ifndef SORT_H
#define SORT_H

void insertionSort(int* arr, int n);

#endif // SORT_H
```

#### 1.2 `sort.cpp`
```cpp
#include "sort.h"

void insertionSort(int* arr, int size) {
    for (int i = 1; i < size; ++i) {
        int key = *(arr + i);  // доступ к элементу массиву через указатель
        int* current = arr + i;

        int j = i - 1;
        while (j >= 0 && *(arr + j) > key) {  // использование указателя для доступа
            *(current) = *(arr + j);  // сдвиг элемента вправо
            --current;  // сдвигаем указатель
            --j;
        }
        *current = key;  // вставляем ключ на нужное место
    }
}
```

#### 1.3 `main.cpp`
```cpp
#include <iostream>
#include "sort.h"

int main() {
    int arr[] = {12, 11, 13, 5, 6};
    int size = sizeof(arr) / sizeof(arr[0]);

    insertionSort(arr, size);

    std::cout << "Отсортированный массив: ";
    for (int i = 0; i < size; ++i) {
        std::cout << arr[i] << " ";
    }
    std::cout << std::endl;

    return 0;
}
```

